import{_ as e,o as l,c as t,ag as i}from"./chunks/framework.C9sp7nFj.js";const p=JSON.parse('{"title":"Emby 缺集扫描","description":"","frontmatter":{},"headers":[],"relativePath":"guide/help/emby-missing.md","filePath":"guide/help/emby-missing.md","lastUpdated":1780491682000}'),r={name:"guide/help/emby-missing.md"};function d(o,a,h,n,s,b){return l(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="emby-缺集扫描" tabindex="-1">Emby 缺集扫描 <a class="header-anchor" href="#emby-缺集扫描" aria-label="Permalink to &quot;Emby 缺集扫描&quot;">​</a></h1><p>Emby 缺集扫描用于检查媒体库里“已经入库但还缺集”的剧集。它适合做周期性补漏，而不是替代订阅工作流的实时状态。</p><p>入口：<code>资源整理 / Emby 缺集扫描</code></p><h2 id="使用前准备" tabindex="-1">使用前准备 <a class="header-anchor" href="#使用前准备" aria-label="Permalink to &quot;使用前准备&quot;">​</a></h2><p>需要先配置：</p><ul><li>Emby 服务地址和 API Key</li><li>TMDB API Key</li></ul><p>缺集判断依赖 TMDB 的标准季集结构。剧集如果没有正确的 TMDBID，系统就很难稳定判断到底缺了哪些集。</p><h2 id="扫描流程" tabindex="-1">扫描流程 <a class="header-anchor" href="#扫描流程" aria-label="Permalink to &quot;扫描流程&quot;">​</a></h2><ol><li>选择 Emby 服务器。</li><li>选择要扫描的媒体库。</li><li>启动扫描。</li><li>等待扫描完成或手动停止。</li><li>查看缺集结果和失败项。</li><li>将需要补找的条目加入监控。</li></ol><p>扫描可能比较耗时，尤其是媒体库很大时。页面会显示当前进度和阶段。</p><h2 id="结果怎么理解" tabindex="-1">结果怎么理解 <a class="header-anchor" href="#结果怎么理解" aria-label="Permalink to &quot;结果怎么理解&quot;">​</a></h2><table tabindex="0"><thead><tr><th>结果</th><th>含义</th></tr></thead><tbody><tr><td>已入库但缺集</td><td>Emby 里已有该剧集，但按 TMDB 标准集数看仍缺少部分集数。</td></tr><tr><td>扫描失败</td><td>当前条目没能完成检查，需要查看失败原因或稍后重试。</td></tr><tr><td>无法加入监控</td><td>通常是缺少 TMDBID 或类型信息，系统无法确认要监控哪个标准条目。</td></tr></tbody></table><p>页面展示的是扫描快照，不是实时 Emby 状态。Emby 后续入库变化，需要重新扫描或通过监控清单刷新确认。</p><h2 id="加入监控" tabindex="-1">加入监控 <a class="header-anchor" href="#加入监控" aria-label="Permalink to &quot;加入监控&quot;">​</a></h2><p>缺集条目可以加入监控。加入后，它会进入监控清单，由监控策略继续寻找缺失资源。</p><p>支持两种方式：</p><ul><li>单条加入监控</li><li>批量把当前筛选结果中可加入的条目加入监控</li></ul><p>批量加入只会新增尚未监控的条目，不会把已经监控的条目删除。</p><h2 id="什么时候重新扫描" tabindex="-1">什么时候重新扫描 <a class="header-anchor" href="#什么时候重新扫描" aria-label="Permalink to &quot;什么时候重新扫描&quot;">​</a></h2><p>建议在这些场景重新扫描：</p><ul><li>Emby 新增了很多剧集</li><li>最近补齐了资源，想确认缺集是否减少</li><li>TMDB 元数据修正后，需要重新计算</li><li>上一次扫描失败较多</li></ul><p>如果只是想查看当前监控条目的状态，优先去 <code>资源获取 / 监控清单</code> 手动刷新，不一定要跑全量缺集扫描。</p><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li>同一时间只能运行一个缺集扫描任务。</li><li>扫描过程中可以停止，但已经写入的部分结果会保留为当前快照。</li><li>缺集扫描不会直接覆盖监控清单里的入库状态。</li><li>删除 Emby 配置时，如果只剩缺集扫描快照引用，系统会允许你确认清理扫描历史后再删除；如果还有豆瓣求片、监控历史等真实业务引用，仍会硬阻断。</li></ul>',24)])])}const c=e(r,[["render",d]]);export{p as __pageData,c as default};
